\begin{figure}
 \includegraphics[width=1\columnwidth]{figures/overview_v1.pdf}

 \caption{An embedded application often involves sensors that collect environmental data, which is then communicated to an edge device. \system\space provides a framework for training foundational models tailored for edge deployment, enabling these models to support a variety of tasks. This work explores training custom foundational models to enhance sensor data analysis. Our approach demonstrates a significantly smaller parameter-sized model than state-of-the-art language models, facilitating high-accuracy sensor data analysis while enabling rapid, local inference on even a constrained edge platform.}

\end{figure}

elements.2412-15304_fig_8f463b03:
\begin{figure}
 \includegraphics[width=\linewidth]{figures/training_v2.pdf}

 \caption{\system\space trains a custom foundational model for deployment at the edge device following a series of steps. It begins by appending a curated dataset with general conversational data. After pre-processing, the dataset is tokenized to pre-train a small model~(30-120M parameter). The pre-trained model undergoes fine-tuning with the custom dataset before deployment on the edge device to support embedded applications.}

\end{figure}

